UPDATE public.backgrounds SET name = 'Heredero Aberrante', description = 'Un trasfondo de EFA', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Historia","Intimidación"]'::jsonb, tool_proficiencies = '["Kit de disfraz"]'::jsonb WHERE name = 'Aberrant Heir';
UPDATE public.backgrounds SET name = 'Acólito', description = 'Un trasfondo del Manual del Jugador', feature_name = 'Amparo de los Fieles', feature_description = 'Como acólito, te ganas el respeto de quienes comparten tu fe y puedes realizar las ceremonias religiosas de tu deidad. Tú y tus compañeros de aventura podéis esperar recibir sanación y cuidados gratuitos en un templo, altar o cualquier otra presencia establecida de tu fe, aunque debéis proporcionar los componentes materiales necesarios para los conjuros. Quienes comparten tu religión te apoyarán (solo a ti) para mantener un estilo de vida modesto.
También puedes tener lazos con un templo específico dedicado a tu deidad o panteón elegido, y tienes una residencia allí. Este podría ser el templo donde solías servir, si mantienes buenas relaciones con él, o un templo donde has encontrado un nuevo hogar. Mientras estés cerca de tu templo, puedes pedir ayuda a los sacerdotes, siempre que la ayuda que solicites no sea peligrosa y mantengas una buena reputación con tu templo.', skill_proficiencies = '["Perspicacia","Religión"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Acolyte';
UPDATE public.backgrounds SET name = 'Acólito', description = 'Un trasfondo del XPHB', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Perspicacia","Religión"]'::jsonb, tool_proficiencies = '["Equipo de calígrafo"]'::jsonb WHERE name = 'Acolyte';
UPDATE public.backgrounds SET name = 'Antropólogo', description = 'Un trasfondo de la Tumba de la Aniquilación', feature_name = 'Lingüista Experto', feature_description = 'Puedes comunicarte con humanoides que no hablen ningún idioma que conozcas. Debes observar a los humanoides interactuar entre sí durante al menos 1 día, tras lo cual aprendes un puñado de palabras, expresiones y gestos importantes, lo suficiente para comunicarte a un nivel rudimentario.', skill_proficiencies = '["Perspicacia","Religión"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Anthropologist';
UPDATE public.backgrounds SET name = 'Arqueólogo', description = 'Un trasfondo de EFA', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Historia","Supervivencia"]'::jsonb, tool_proficiencies = '["Herramientas de cartógrafo"]'::jsonb WHERE name = 'Archaeologist';
UPDATE public.backgrounds SET name = 'Arqueólogo', description = 'Un trasfondo de Tumba de Aniquilación.', feature_name = 'Conocimiento Histórico', feature_description = 'Cuando entras en una ruina o mazmorra, puedes determinar correctamente su propósito original y la identidad de sus constructores, ya sean enanos, elfos, humanos, yuan-ti u otra raza conocida. Además, puedes determinar el valor monetario de objetos de arte de más de un siglo de antigüedad.', skill_proficiencies = '["Historia","Supervivencia"]'::jsonb, tool_proficiencies = '["Una herramienta a elegir"]'::jsonb WHERE name = 'Archaeologist';
UPDATE public.backgrounds SET name = 'Vagabundo Astral', description = 'Un trasfondo de AAG', feature_name = 'Contacto Divino', feature_description = 'Obtienes la dote Iniciado en Magia del Manual del Jugador y debes elegir Clérigo para la dote.
En el Mar Astral, te cruzaste con una deidad errante. El encuentro fue breve y no violento, pero te dejó una impresión duradera. Esta deidad consideró oportuno compartir contigo un secreto o una pizca de saber cósmico arcano. Trabaja con tu DM para determinar los detalles de este conocimiento y su impacto en la campaña.
Tira en la tabla de Contacto Divino para determinar qué deidad encontraste, o trabaja con tu DM para identificar una elección más adecuada.', skill_proficiencies = '["Perspicacia","Religión"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Astral Drifter';
UPDATE public.backgrounds SET name = 'Atleta', description = 'Un trasfondo de Mitos de Odiseas de Theros.', feature_name = 'Ecos de Victoria', feature_description = 'Has atraído la admiración entre espectadores, compañeros atletas y entrenadores en la región que albergó tus pasadas victorias atléticas. Cuando visitas cualquier asentamiento dentro de un radio de 100 millas de donde creciste, hay un 50% de probabilidad de que encuentres a alguien que te admire y esté dispuesto a proporcionarte información o refugio temporal. Entre aventuras, podrías competir en eventos atléticos suficientes como para mantener un estilo de vida cómodo, de acuerdo con la actividad de tiempo libre "Ejercer una profesión" del capítulo 8 del Manual del Jugador.', skill_proficiencies = '["Acrobacias","Atletismo"]'::jsonb, tool_proficiencies = '["Vehículos (terrestres)"]'::jsonb WHERE name = 'Athlete';
UPDATE public.backgrounds SET name = 'Charlatán', description = 'Un trasfondo del Manual del Jugador', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Engaño","Juego de Manos"]'::jsonb, tool_proficiencies = '["Equipo de falsificación"]'::jsonb WHERE name = 'Charlatan';
UPDATE public.backgrounds SET name = 'Bucanero Chondathan', description = 'Un trasfondo de FRHoF', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Atletismo","Juego de Manos"]'::jsonb, tool_proficiencies = '["Herramientas de tejedor"]'::jsonb WHERE name = 'Chondathan Freebooter';
UPDATE public.backgrounds SET name = 'Guardia de la Ciudad', description = 'Un trasfondo originario de la Guía del Aventurero de la Costa de la Espada.', feature_name = 'Ojo del Vigilante', feature_description = 'Tu experiencia haciendo cumplir la ley y tratando con infractores te otorga una percepción de las leyes locales y los criminales. Puedes encontrar fácilmente el puesto de avanzada local de la guardia o una organización similar, y con la misma facilidad identificar los centros de actividad criminal en una comunidad, aunque es más probable que seas bienvenido en los primeros lugares que en los segundos.', skill_proficiencies = '["Atletismo","Perspicacia"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'City Watch';
UPDATE public.backgrounds SET name = 'Artesano de Clan', description = 'Un trasfondo de la Guía del Aventurero de la Costa de la Espada.', feature_name = 'Respeto de la Gente Recia', feature_description = 'Por muy respetados que los artesanos de clan sean entre los forasteros, nadie los estima tan altamente como lo hacen los enanos. Siempre tienes alojamiento y manutención gratuitos en cualquier lugar donde residan enanos de escudo o enanos de oro, y los individuos de dicho asentamiento podrían competir entre sí para determinar quién puede ofrecerte a ti (y posiblemente a tus compañeros) el mejor alojamiento y asistencia.', skill_proficiencies = '["Historia","Perspicacia"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Clan Crafter';
UPDATE public.backgrounds SET name = 'Erudito Claustral', description = 'Un trasfondo del Sword Coast Adventurer''s Guide.', feature_name = 'Acceso a la Biblioteca', feature_description = 'Aunque otros a menudo deben soportar extensas entrevistas y considerables tarifas para obtener acceso incluso a los archivos más comunes de tu biblioteca, tú tienes acceso libre y fácil a la mayor parte de la biblioteca. Sin embargo, esta podría tener repositorios de saber que son demasiado valiosos, mágicos o secretos como para permitir a cualquiera un acceso inmediato.
Tienes un conocimiento práctico del personal y la burocracia de tu claustro, y sabes cómo navegar esas conexiones con cierta facilidad.
Además, es probable que recibas un trato preferencial en otras bibliotecas de los Reinos, como cortesía profesional a un colega erudito.', skill_proficiencies = '["Historia","Una habilidad a elegir"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Cloistered Scholar';
UPDATE public.backgrounds SET name = 'Refugiado de Cormanthor', description = 'Un trasfondo de ALRageOfDemons', feature_name = 'Amparo del Clero Élfico', feature_description = 'Los clérigos de Elventree han prometido cuidar de los refugiados de Cormanthor. Te ayudarán cuando puedan, incluyendo la provisión gratuita de curación y cuidado para ti y tus compañeros en templos, santuarios y otras presencias establecidas en Elventree. También te proporcionarán (pero solo a ti) un estilo de vida pobre. Nota: Este rasgo es una variante del rasgo Acólito.', skill_proficiencies = '["Naturaleza","Supervivencia"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Cormanthor Refugee';
UPDATE public.backgrounds SET name = 'Criminal', description = 'Un trasfondo del Manual del Jugador', feature_name = 'Contacto Criminal', feature_description = 'Tienes un contacto fiable y digno de confianza que actúa como tu enlace con una red de otros criminales. Sabes cómo enviar y recibir mensajes de tu contacto, incluso a grandes distancias; en concreto, conoces a los mensajeros locales, a los maestros de caravanas corruptos y a los marineros de mala reputación que pueden entregarte mensajes.', skill_proficiencies = '["Engaño","Sigilo"]'::jsonb, tool_proficiencies = '["Herramientas de ladrón"]'::jsonb WHERE name = 'Criminal';
UPDATE public.backgrounds SET name = 'Operativo Dimir', description = 'Un trasfondo de GGR', feature_name = 'Falsa Identidad', feature_description = 'Tienes más de una identidad. La que adoptas la mayor parte del tiempo te hace parecer miembro de un gremio diferente a la Casa Dimir. Posees documentación, conocidos establecidos y disfraces que te permiten asumir esa personalidad e integrarte en el gremio secundario. Cuando lo desees, puedes abandonar esta identidad y mimetizarte con las masas sin gremio de la ciudad. Considera por qué estás infiltrado en el gremio secundario. Crea una historia con tu DM, inspirada por una tirada en la siguiente tabla o eligiendo una razón que te convenga.', skill_proficiencies = '["Engaño","Sigilo"]'::jsonb, tool_proficiencies = '["Kit de disfraz"]'::jsonb WHERE name = 'Dimir Operative';
UPDATE public.backgrounds SET name = 'Víctima de Dragón', description = 'Un trasfondo de ALCurseOfStrahd', feature_name = 'Cicatriz de Dragón', feature_description = 'Durante varios meses, fuiste sometido a torturas mágicas y mundanas a manos de Vorgansharax y sus secuaces. Estos experimentos te han dejado horriblemente desfigurado, pero te señalan como un superviviente de la Virulencia Mutilada. Esto te otorga cierta fama y notoriedad, ya que aquellos que conocen tu terrible calvario están deseosos de escuchar la historia de primera mano, pero dificulta disfrazar tu apariencia y esconderte de miradas curiosas.
Puedes aprovechar esta atención para obtener acceso a personas y lugares a los que, de otro modo, no tendrías acceso, tanto para ti como para tus compañeros. Nobles, eruditos, magos y aquellos que buscan desentrañar los secretos de la Virulencia Mutilada estarían todos deseosos de escuchar tu relato de supervivencia, y de aprender qué secretos (si los hubiera) podrías poseer, y/o de estudiar tu aflicción con gran interés. Sin embargo, temes que tus aflicciones no sean completamente mundanas y que la Virulencia Mutilada pueda tener todavía alguna razón nefasta para permitir tu escape, ya que tus cicatrices arden con furia ácida y parecen retorcerse bajo tu piel en ocasiones. Nota: Este rasgo es una variante del rasgo Viajero Lejano.', skill_proficiencies = '["Intimidación","Supervivencia"]'::jsonb, tool_proficiencies = '["Vehículos (acuáticos)","Elige una herramienta","Vehículos (terrestres)"]'::jsonb WHERE name = 'Dragon Casualty';
UPDATE public.backgrounds SET name = 'Cultista del Dragón', description = 'Has dedicado tu vida al servicio de los dragones, uniéndote a un culto dracónico que busca su gloria o resurgimiento. Operas en las sombras, llevando a cabo sus designios con astucia y sigilo.', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Engaño","Sigilo"]'::jsonb, tool_proficiencies = '["Suministros de calígrafo"]'::jsonb WHERE name = 'Dragon Cultist';
UPDATE public.backgrounds SET name = 'Minero de Earthspur', description = 'Un trasfondo de ALElementalEvil', feature_name = 'Minero de las Profundidades', feature_description = 'Estás acostumbrado a navegar por los lugares profundos de la tierra. Nunca te pierdes en cuevas o minas si has visto un mapa preciso de ellas o las has recorrido antes. Además, eres capaz de conseguir agua fresca y comida para ti y hasta cinco personas adicionales cada día si estás en una mina o cuevas naturales. Nota: Este rasgo es una variante del rasgo Forastero.', skill_proficiencies = '["Atletismo","Supervivencia"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Earthspur Miner';
UPDATE public.backgrounds SET name = 'Cuidador del Enclave Esmeralda', description = 'Un trasfondo de FRHoF', feature_name = NULL, feature_description = NULL, skill_proficiencies = '["Naturaleza","Supervivencia"]'::jsonb, tool_proficiencies = '["Kit de herboristería"]'::jsonb WHERE name = 'Emerald Enclave Caretaker';
UPDATE public.backgrounds SET name = 'Animador', description = 'Trasfondo del Manual del Jugador', feature_name = 'Por Petición Popular', feature_description = 'Siempre puedes encontrar un lugar donde actuar, normalmente en una posada o taberna, pero quizás con un circo, en un teatro o incluso en la corte de un noble. En un lugar así, recibes alojamiento y comida gratuitos de un nivel modesto o cómodo (según la calidad del establecimiento), siempre y cuando actúes cada noche. Además, tu actuación te convierte en una especie de figura local. Cuando los extraños te reconocen en una ciudad donde has actuado, normalmente te cogen cariño.', skill_proficiencies = '["Acrobacias","Interpretación"]'::jsonb, tool_proficiencies = '["Kit de disfraz"]'::jsonb WHERE name = 'Entertainer';
UPDATE public.backgrounds SET name = 'Agente de Facción', description = 'Un trasfondo del SCAG', feature_name = 'Refugio Seguro', feature_description = 'Como agente de facción, tienes acceso a una red secreta de simpatizantes y operativos que pueden proporcionarte asistencia en tus aventuras. Conoces un conjunto de signos secretos y contraseñas que puedes usar para identificar a dichos operativos, los cuales pueden proporcionarte acceso a una casa segura oculta, alojamiento y comida gratis, o asistencia para encontrar información. Estos agentes nunca arriesgan sus vidas por ti ni arriesgan revelar sus verdaderas identidades.', skill_proficiencies = '["Perspicacia","Elegir de una lista"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Faction Agent';
UPDATE public.backgrounds SET name = 'Apostador', description = 'Un trasfondo de IA', feature_name = 'Nunca Me Digas Las Probabilidades', feature_description = 'Las probabilidades son tu pan de cada día. Durante las actividades de tiempo de inactividad que involucren juegos de azar o el cálculo de probabilidades para el mejor plan, puedes obtener una noción sólida de qué elección es probablemente la mejor y qué oportunidades parecen demasiado buenas para ser verdad, a discreción del DM.', skill_proficiencies = '["Engaño","Perspicacia"]'::jsonb, tool_proficiencies = '[]'::jsonb WHERE name = 'Gambler';
